sys_script_include.script:
var WDServiceNowSynch = Class.create();
WDServiceNowSynch.prototype = {
    initialize: function() {},
/* 
    Parent funciton
     */
    transform: function(request_body) {
		request_body['worklogEntries'] = this.processWorkNotes(request_body.worklogEntries);
        var body = this.buildBody(request_body);
        var returnBody = {};
        var syncData = this.transformData(body);
        var parsedresponse = JSON.parse(syncData[1]);

       if (syncData[0] == 201) {
            returnBody['number'] = parsedresponse['result'][0]['display_value'];
            returnBody['sys_id'] = parsedresponse['result'][0]['sys_id'];
            returnBody['status'] = parsedresponse['result'][0]['status'];

            returnBody['status_code'] = parsedresponse['result'][0]['status'] == 'inserted' ? 201 : 200;

            if (parsedresponse['result'][0]['status'] == 'ignored') {
                returnBody['status_message'] = parsedresponse['result'][0]['status_message'];
            }

            this._log('Return body', JSON.stringify(returnBody));
            return returnBody;
        }
    },

	transformRequest: function(request_body) {
		this._log('Request create input :' , JSON.stringify(request_body));
		var returnBody = {};
		var ci_sysId;
		var c_ci = new GlideRecord('cmdb_ci');
		c_ci.addQuery('name',request_body.partnerDeviceId.toString());
		c_ci.query();
		if(c_ci.next()){
			ci_sysId = c_ci.sys_id;
		}

		var serv_name;
		var serv = new GlideRecord('x_mydes_cat_data_x_wd_itsm_utilities');
		serv.addQuery('category','request_service_line');
		serv.addQuery('request_service_line',request_body.service.toString());
		serv.query();
		if(serv.next()){
			serv_name = serv.request_service.u_name;
			//gs.info('sys_id ' + serv_sysid );
			gs.info('name :' + serv.request_service.u_name);
		}

        var cartId = GlideGuid.generate(null);
		var cart = new Cart(cartId);
		//add your requested item to the cart by sys_id of the catalog item
		var item = cart.addItem('94d707291b645d50538aa9362a4bcb17', 1);

		//fill in the variables on the request item form
		//cart.setVariable(item, "short_description", "ATT Ticket ID: " + request_body.id +" IssueType: "+request_body.issueType + "Service: " + request_body.service + " Device ID: " + request_body.partnerDeviceId);
		cart.setVariable(item, "is_it_a_policy_request", "No");
		cart.setVariable(item, "service", serv_name);
		cart.setVariable(item, "issue_type", request_body.issueType);
		cart.setVariable(item, "service_line", request_body.service);
		cart.setVariable(item, "description", request_body.issueDescription);
		cart.setVariable(item, "impacted_ci", ci_sysId);
		cart.setVariable(item, "wd_itsm_ticket_id",request_body.id);
		var rc = cart.placeOrder();
		if(rc){ 
			returnBody['Parent Request Number'] = rc.number;
			returnBody['Parent Request sys_id'] = rc.sys_id;
			returnBody['status'] = 'inserted';
			returnBody['status_code'] = 200;
		}else {
			returnBody['message'] = "Request not created in ServiceNow. Please contact the support team.";
			returnBody['status'] = 'error';
			returnBody['status_code'] = 500;
		}

			this._log('Return body in transformRequest', JSON.stringify(returnBody));
            return returnBody;
    },

	//Handle updates coming on Request Task
	transformRequestUpdate: function(request_body, req_task) {
		this._log('Input request update',JSON.stringify(request_body));
		var state_value;
		switch(request_body.statusVal.toString()) {
				case "New":
				state_value="1";
				break;
				case "Assigned":
				state_value="2";
				break;
				case "Work In Progress":
				state_value="2";
				break;
				case "Pending":
				state_value="11";
				break;
				case "Resolved, Pending Closure":
				state_value="3";
				break;
				case "Closed":
				state_value="3";
				break;
			}
		var rt_processed;
		var isActiveTicket;
		var returnBody = {};
		var rt = new GlideRecord('sc_task');
		rt.addQuery('number',req_task.toString());
		//rt.addActiveQuery();
		rt.query();
		if(rt.next()){
			//Process only Active requests else ignore
			if(rt.active == false){ 

				rt.work_notes = "ATT ITSM system tried to update the inactive/closed request and the updates are ignored. Here is the request Payload:- \n" + JSON.stringify(request_body);
				isActiveTicket = false;
			}
			else{
			//process IssueDescription updates
				if(request_body.issueDescription){
					rt.variables.description = request_body.issueDescription;
					rt.description = request_body.issueDescription;
				}

				//process statusVal updates and add a default assignee to stop the response SLA clock.
				if(request_body.statusVal){
					rt.state = state_value;
					if(rt.assigned_to=='' && (request_body.statusVal=='Assigned'|| request_body.statusVal=='Work In Progress')){
						var ta = new GlideRecord('x_mydes_cat_data_x_wd_itsm_utilities');
						ta.addEncodedQuery('category=ticket_assignee^active=true');
						ta.addQuery('assignment_group', rt.assignment_group);
						ta.query();
						if(ta.next()){
							rt.assigned_to = ta.default_assignee;
						}						
					}	
				}


				//process partnerDeviceId updates
				if(request_body.partnerDeviceId){

					var c_ci = new GlideRecord('cmdb_ci');
					c_ci.addQuery('name',request_body.partnerDeviceId.toString());
					c_ci.query();
					if(c_ci.next()){
						rt.variables.impacted_ci = c_ci.sys_id;
						rt.cmdb_ci = c_ci.sys_id;
					}

				}


				//process service updates
				if(request_body.service){
					var serv_name;
					var serv = new GlideRecord('x_mydes_cat_data_x_wd_itsm_utilities');
					serv.addQuery('category','request_service_line');
					serv.addQuery('request_service_line',request_body.service.toString());
					serv.query();
					if(serv.next()){
						rt.variables.service = serv.request_service.u_name;
						rt.variables.service_line = request_body.service;
						}
				}


				//process worklogEntries updates
				if(request_body.worklogEntries){
					rt.work_notes = this.processWorkNotes(request_body.worklogEntries); 
				}
			}
			rt_processed = rt.update();
			isActiveTicket = true;
		}
		if(rt_processed && isActiveTicket == false){
			returnBody['status'] = 'ignored';
			returnBody['status_code'] = 200;
		}else if(rt_processed && isActiveTicket == true){
			returnBody['Request Task Number'] = rt.number;
			returnBody['Request Task sys_id'] = rt.sys_id;
			returnBody['status'] = 'updated';
			returnBody['status_code'] = 200;
		}else {
			returnBody['message'] = "Request not updated in ServiceNow. Please contact the support team.";
			returnBody['status'] = 'error';
			returnBody['status_code'] = 500;
		}

		return returnBody;

	},

    /*Build the input request body for the import set API to create/update incident
     *Appending the source object keys with u_
     */

    buildBody: function(body) {
        var restBody = {};

        for (fields in body) {
            restBody['u_' + fields.toLowerCase()] = body[fields];
        }

        this._log('Source body', JSON.stringify(restBody));

        return restBody;
    },

    transformData: function(input_data) {
        this._log('transformData', JSON.stringify(input_data));
		//input_data['u_worklogentries'] = this.processWorkNotes(input_data.worklogEntries);
		var instance_name = gs.getProperty('instance_name');

        var request = new sn_ws.RESTMessageV2();
        request.setEndpoint('https://'+ instance_name +'.service-now.com/api/now/import/u_wd_itsm_incident_inbound');
        request.setHttpMethod('POST');

        //Eg. UserName="admin", Password="admin" for this code sample.
        var user = 'WD-APIUser';
        var password = gs.getProperty('ATT.itsm.ticketing.bridge.passwd');

        request.setBasicAuth(user, password);
        request.setRequestHeader('Accept', 'application/json');
        request.setRequestHeader('Content-Type', 'application/json');
        request.setRequestBody(JSON.stringify(input_data));
        var response = request.execute();
        var statusCode = response.getStatusCode() ? response.getStatusCode() : response.getErrorCode();

        var respBody = statusCode == 201 ? response.getBody() : response.getErrorMessage();
        this._log('Status Code', statusCode);
        this._log('ResponseBody', respBody);

        return [statusCode, respBody];
    },

	//update ServiceNow Incident number in parterTicketID at ITSM side

	updateITSMPartnerTicketId: function(ticket_obj){

		var base64_token = 'Basic '+gs.getProperty('ATT.itsm.base64.token');
		var end_point = 'https://services.sec.ATT.com/micro/ticket_detail/' + ticket_obj.correlation_id.toString();
		var request = new sn_ws.RESTMessageV2();
		request.setEndpoint(end_point);
		request.setHttpMethod('PATCH');
		var req_body = {
			"partnerTicketId": ticket_obj.number.toString()
		};

		request.setRequestHeader('Content-Type', 'application/json');
		request.setRequestHeader('Authorization', base64_token);
		request.setRequestBody(JSON.stringify(req_body));
		var response = request.execute();
		return [response];
	},

	createITSMTicketFromIncident: function(incident_input){
		try { 
		var r = new sn_ws.RESTMessageV2('ATT ITSM', 'POST');
		r.setStringParameterNoEscape('api_key', 'Basic '+ gs.getProperty('ATT.itsm.base64.token'));
		var sevMatrix;
		switch(incident_input.priority.toString()) {
				case "1":
				sevMatrix="SEV1";
				break;
				case "2":
				sevMatrix="SEV2";
				break;
				case "3":
				sevMatrix="SEV3";
				break;
				case "4":
				sevMatrix="SEV4";
				break;
				default:
				sevMatrix="SEV4";
			}
		var temp_service;
		var temp_service_id;
		var gr = new GlideRecord('x_mydes_cat_data_x_wd_itsm_utilities');
			gr.addQuery('category','service_selection');
			gr.addActiveQuery();
			gr.addQuery('assignment_group',incident_input.assignment_group);
			gr.query();
			if(gr.next()){
				temp_service = gr.service.name;
				temp_service_id = gr.service.sys_id;
			}else{
				temp_service = gr.getProperty('');
			}

		var issue;
			if(incident_input.category=='ATT ITSM - Incident' && incident_input.subcategory!=''){
				issue = incident_input.subcategory.toString();
			}else{
				issue = gs.getProperty('ATT.itsm.default.issuetype').toString();
			}

		var body = { "severityVal": sevMatrix.toString(),
					"issueDescription": incident_input.description.toString(),
					"nature": "Service Incident",
					"issueType": issue.toString(),
					"service": temp_service.toString(),
					"partnerTicketId": incident_input.number.toString(),
					"blockEventNotification": "Block"
					};
			this._log('Incident Outbound POST  : ' , JSON.stringify(body));
			r.setRequestBody(JSON.stringify(body));
			var response = r.execute();

			//update Corelation ID
			var statusCode = response.getStatusCode();
			if((statusCode==200||statusCode==201)&& incident_input.correlation_id == ''&& !incident_input.isNewRecord() ){
				incident_input.correlation_id = JSON.parse(response.getBody()).id.toString();
				incident_input.correlation_display = "ATT ITSM";
				incident_input.u_wd_itsm_service = temp_service_id;
				incident_input.update();
			}




		}
		catch(ex) {
			var message = ex.message;
		}
		return [response,temp_service_id];
	},

	createITSMTicketFromRequest: function(req_task){
		try { 
		var r = new sn_ws.RESTMessageV2('ATT ITSM', 'POST');
		r.setStringParameterNoEscape('api_key', 'Basic '+ gs.getProperty('ATT.itsm.base64.token'));
		var partnerDevices = [];
		var partnerDevices_arr = req_task.request_item.variables.impacted_ci.getDisplayValue().toString().split(',');
			for (var i=0; partnerDevices_arr.length > i; i++){
				partnerDevices.push({"partnerDeviceId": partnerDevices_arr[i].trim(), "status":"Active"});
			}

		var body = {"contactName" : req_task.opened_by.name.toString(),                  //Name and email for current user opening the task
					"contactEmail" : req_task.opened_by.email.toString(),
					"severityVal": "SEV4",                                          //"SEV4", hardcoded for Service Request created in ServiceNow
					"issueDescription": req_task.request_item.variables.description.toString(),
					"nature": "Service Request",                                                //Hardcoded value for Service Request
					"issueType": req_task.request_item.variables.issue_type.toString(),
					"service": req_task.request_item.variables.service_line.toString(),
					"partnerTicketId": req_task.number.toString(),
					"devices": partnerDevices,
				//	"partnerDeviceId" : req_task.request_item.variables.impacted_ci.name.toString(),
					"blockEventNotification": "Block"
					};
			this._log('Request Outbound POST  : ' , JSON.stringify(body));
			r.setRequestBody(JSON.stringify(body));
			var response = r.execute();
			var statusCode = response.getStatusCode();

			if((statusCode==200||statusCode==201)&& req_task.correlation_id == '' && !req_task.isNewRecord()){
				this._log(' Request Correlation ID  : ' , 'Inside IF');
				var id = JSON.parse(response.getBody()).id.toString();
				req_task.correlation_id = id;
				req_task.correlation_display = "ATT ITSM";
				req_task.update();

				var ri = new GlideRecord('sc_req_item');
				ri.get(req_task.request_item);
				ri.variables.wd_itsm_ticket_id =  id;
				ri.update();
			}

		}
		catch(ex) {
			var message = ex.message;
		}
		return [response];
	},

	updateITSMTicketFromIncident_buildBody: function(current_state, previous_state){
		var body={};
		var stateMap;
		switch(current_state.state.toString()){
				case "1":
				stateMap="New";
				break;
				case "2":
				stateMap="Work In Progress";
				break;
				case "3":
				stateMap="Pending";
				break;
				case "6":
				stateMap="Resolved, Pending Closure";
				break;
				//Update Set- GRC:Global_ATTITSM_JP_18/10/2023
// 				case "7":
// 				stateMap="Closed";
// 				break;
				//code after Team requested to add cancelled state
				case "8":
				stateMap="Resolved, Pending Closure";
				break;//GRC:Global_ATTITSM_JP_18/10/2023


		}
		var sevMatrix;
		switch(current_state.priority.toString()) {
				case "1":
				sevMatrix="SEV1";
				break;
				case "2":
				sevMatrix="SEV2";
				break;
				case "3":
				sevMatrix="SEV3";
				break;
				case "4":
				sevMatrix="SEV4";
				break;
				default:
				sevMatrix="SEV4";
			}

			if(current_state.priority.changes()){
				body['severityVal'] = sevMatrix.toString();
			}
			if(current_state.description.changes()){
				body['issueDescription'] = current_state.description.toString();
			}
			if(current_state.state.changes()){
				body['statusVal'] = stateMap.toString();
			}
			if(current_state.work_notes.changes()){
				body['worklogText'] = current_state.work_notes.getJournalEntry(1);
			}
			body['blockEventNotification']= "Block";

			this._log('updateITSMTicketFromIncident_buildBody' , JSON.stringify(body));

			return body;

	},

	updateITSMTicketFromIncident: function(current_state, body){
		try { 
			var r = new sn_ws.RESTMessageV2('ATT ITSM', 'PATCH');
			r.setStringParameterNoEscape('ticket_id',current_state.correlation_id.toString() );
			r.setStringParameterNoEscape('api_key', 'Basic '+ gs.getProperty('ATT.itsm.base64.token'));
			this._log('updateITSMTicketFromIncident' , JSON.stringify(body));	

			r.setRequestBody(JSON.stringify(body));
			var response = r.execute();
			var responseBody = response.getBody();
			this._log('Response updateITSMTicketFromIncident' , responseBody);
			var httpStatus = response.getStatusCode();
		}
		catch(ex) {
			var message = ex.message;
		}
		return [response];
	},
