	//Code to handle Errors occuring during outbound API calls
	errorHandling: function(called_function, current_record, req_body){
		var res ; 
		if(called_function == 'updateITSMPartnerTicketId'){
			res = this.updateITSMPartnerTicketId(current_record);
		}else if(called_function == 'updateITSMTicketFromIncident'){
			res = this.updateITSMTicketFromIncident(current_record, req_body);
		}else if(called_function == 'createITSMTicketFromIncident'){
			res = this.createITSMTicketFromIncident(current_record);
		}
		return res;
		//------------------------Old Method of Error Handling------------------------
		/*var i = 1;
		var j = 6;
		while (i <= j) {
			gs.sleep(300000);      //sleep for 5 mins to make sure the call is made every 5 mins
			//gs.info('Make API call and retrieve the status code: '+ input_record.number + ' and the count is : '+ i );
			var res = this.updateITSMIncident(input_record);
			var statusCode = res.code.toString();
			this._log(i +' : Re-attempt from Error Handling', res.getBody());

			if(statusCode =='200' || statusCode =='201'){
				break;
				}

			if(i==j){                               
				//gs.info('Create an Incident'); 
				var gr = new GlideRecord('incident');
				gr.initialize();
				gr.caller_id = input_record.caller_id;
				gr.category ='it_infrastructure';
				gr.subcategory = 'network';
				gr.short_description = 'ServiceNow-ATT ITSM Integration failed for Incident : ' + input_record.number;
				gr.description = res.getBody();
				gr.impact = '2';
				gr.urgency = '2';
				gr.assignment_group = 'c8a75ede1b337340dcfbbb7acd4bcb2e';
				gr.insert();


				}

			i++;
			}	*/	
		//-----------------End Comments---------------------------------------------
	},


	errorHandlingForRequest: function(called_function, current_req_task, request_body){
		var res ; 
		if(called_function == 'updateITSMPartnerTicketId'){
			res = this.updateITSMPartnerTicketId(current_req_task);
		}else if(called_function == 'updateITSMTicketFromRequest'){
			res = this.updateITSMTicketFromRequest(current_req_task, request_body);
		}else if(called_function == 'createITSMTicketFromRequest'){
			res = this.createITSMTicketFromRequest(current_req_task);
		}
		return res;

	},

	//Check if the incident coming from ATT ITSM is Valid or not. Now applicable in case of Service Requests

	checkValidPostCall: function(body){
		var gr = new GlideRecord('x_mydes_cat_data_x_wd_itsm_utilities');
		gr.addQuery('category','exclusion_list'),
		gr.addQuery('active', 'true');
		gr.addQuery('service.name',body.service.toString());
		gr.addQuery('issue_type.issue_type',body.issueType.toString());
		gr.query();
		if(gr.next()){
			gr.notes='API Call for creating the '+body.nature.toString()+ ' is ignored for below record as it was matching this exclusion record.\n JSON Payload from ATT ITSM : ' + JSON.stringify(body);
			gr.update();
			return false;
		}else{
			return true;
		}
	},


	//Check if its a valid post call and make sure there is a record available in the system.

	checkValidPatchCall: function(req_body){
	if(req_body.partnerTicketId){
		var p_id = req_body.partnerTicketId.toString();

			if(p_id.includes('INC')){
				return [true,'Service Incident'];
			}else{
				return [true,'Service Request', req_body.partnerTicketId.toString()];
			}
	}else{
		var gr = new GlideRecord('task');
		gr.addQuery('correlation_id',req_body.id);
		gr.query();
		if(gr.next()){ 
				if(gr.sys_class_name == 'incident'){
					return [true,'Service Incident'];
				}else{
					return [true,'Service Request',gr.number];
				}
			}
		else {
			return [false,''];
			}
		}
	},

	//Make an API call to fetch attachment from ATT ITSM and upload to ServiceNow Record
	getAttachment: function(reqBody, table_type){

		var attach_id = reqBody.attachments[0].id;
		var attach_name = reqBody.attachments[0].attachment;
		var wd_itsm_record_id = reqBody.id;
		try { 
			var r = new sn_ws.RESTMessageV2('ATT ITSM', 'Attachment GET');
			r.setStringParameterNoEscape('api_key', 'Basic '+ gs.getProperty('ATT.itsm.base64.token'));
			r.setStringParameterNoEscape('attachment_id', attach_id);
			var response = r.execute();
			var responseBody = response.getBody();
			var httpStatus = response.getStatusCode();
			this._log('Attachment Body (From ATT ITSM)', responseBody.toString());

			//convert and upload the attachment to serviceNow incident or sc_task
				if(httpStatus==200 || httpStatus==201){
					var rec;
					var ticket_number;
					var sna = null;
					if(table_type=='Service Incident'){
						rec = new GlideRecord('incident');
					}else{
						rec = new GlideRecord('sc_task');	
					}

					rec.addQuery('correlation_id', wd_itsm_record_id);
					rec.query();
					if(rec.next()){
						gs.info('ATT ITSM sna - its coing in IF');
							var base64File= responseBody.toString(); //The huge base64Encoded string
							var file_name = attach_name;
							var contentType = "";
							var DecodedBytes = GlideStringUtil.base64DecodeAsBytes(base64File); //Decodes the base64Encoded Data in Bytes.

							var attach = new GlideSysAttachment();
							sna = attach.write(rec, file_name, contentType, DecodedBytes);
						}
					}

				if(sna==null || httpStatus !=200){
					var attachemnt_inputs={};
							attachemnt_inputs['ticket_number']= reqBody.partnerTicketId!=null ? reqBody.partnerTicketId+' (ServiceNow)' : reqBody.id+' (ATT ITSM)';
							attachemnt_inputs['status_code'] = httpStatus != 200 || sna==null? 500 : httpStatus;
							attachemnt_inputs['call_type']= 'GET';
							attachemnt_inputs['request_payload'] = JSON.stringify(reqBody);
							attachemnt_inputs['returned_response']= httpStatus != 200 ? response.getBody() :' File Retrieved from ATT ITSM but No file is attached in ServiceNow ticket.' ;

			sn_fd.FlowAPI.getRunner().subflow('global.wd_itsm__error_handling_for_attachments').inBackground().withInputs(attachemnt_inputs).run();
						}

		}catch(ex) {
			var message = ex.message;
		}
		return responseBody;
	},

	isValidATTITSMAttachment : function(incident_sysid){
		var gr = new GlideRecord('incident');
		gr.get(incident_sysid);
		if(gr.correlation_display == "ATT ITSM" && gr.correlation_id !=''){
			return true;
		}else{
			return false;
		}

	},

	isValidATTITSMAttachmentForRequest : function(request_sysid){
		var gr = new GlideRecord('sc_task');
		gr.get(request_sysid);
		if(gr.correlation_display == "ATT ITSM" && gr.correlation_id !=''){
			return true;
		}else{
			return false;
		}

	},
	//Process Worknotes JSON Array coming from ATT ITSM to a readable format
	processWorkNotes : function(input_wn){
		//gs.info('ATT ITSM JSON Worknotes input : ' +input_wn[0].text  + ' : ' + input_wn.length );
		var formatted_wn = '';
		for(var i=0; i<input_wn.length; i++){
			var a = input_wn[i].text.split('\n');

			var x = 'ATT ITSM UserName : ' + input_wn[i].username + '\n';
			var y ='ATT ITSM WorkLogs : ';

			for(var j=0; j<a.length; j++){
				y = y+ a[j] + '\n';
			}    
			formatted_wn = formatted_wn + x + y + '\n';
		}

		//gs.info('ATT ITSM  Worknotes formatted output : ' +formatted_wn);
		return formatted_wn; 

	},

	getCIsysIds : function(){
		var arr = [];
		var gr = new GlideRecord('label_entry');
		gr.addEncodedQuery('label.name=ATT ITSM Managed');
		gr.query();
		while(gr.next()){
			arr.push(gr.table_key.toString());
		}
		return 'sys_idIN' + arr.join(',');
	},

	showErrorMessage : function(){
		gs.addErrorMessage('There is an issue while sending ticket details to ATT ITSM. System will automatically re-attempt sending the details and If it fails again then ServiceNow will create an Incident for the support group after 10 minutes.');
	},

    //Print log statements when the property is set to true
    _log: function(message, content) {
        if (gs.getProperty('ATT.itsm_inbound.incident.log')) {
            gs.info('ATT ITSM  ' + message + ' : ' + content);
        }
    },

    type: 'WDServiceNowSynch'
};
